#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
Install the Track2 next-step branch-fusion pipeline into this repository.
Run from the repository root:
    python install_nextstep_branch_fusion.py
"""
from __future__ import annotations
from pathlib import Path
import base64, io, shutil, subprocess, sys, zipfile
BUNDLE_B64 = """

""".strip()
ROOT = Path.cwd()
REQUIRED = ["model.py", "dataset.py", "config.py"]
CORE_FILES = [
    "main_train_all95_v2.py",
    "patch_model_stable_cross_all95.py",
    "generate_score_multicrop_plus.py",
    "train_type_classifier_track2.py",
    "score_type_classifier_track2.py",
    "tune_branch_fusion.py",
    "apply_branch_fusion.py",
    "apply_fixed_threshold.py",
    "diagnose_type_posterior.py",
    "tune_soft_type_threshold.py",
    "apply_soft_type_threshold.py",
    "tune_calibrated_type_threshold.py",
    "apply_calibrated_type_threshold.py",
]
OBSOLETE = [
    "patch_t2_crop_training.py",
    "patch_main_train_crop_safe.py",
    "patch_main_train_crop_robust.py",
    "repair_main_train_loop_crop.py",
    "patch_main_train_weak3_save.py",
    "patch_main_train_singing_safe_save.py",
    "patch_model_stable_cross_singing_safe.py",
    "tune_type_posterior_calibrator.py",
    "apply_type_posterior_calibrator.py",
    "fuse_singing_guard.py",
]

def _check_root():
    miss=[x for x in REQUIRED if not (ROOT/x).exists()]
    if miss:
        raise SystemExit(f"[error] run in repo root; missing {miss}")

def _backup(path: Path, backup_dir: Path):
    if path.exists():
        dst=backup_dir/path.name
        if not dst.exists():
            shutil.copy2(path,dst)
            print(f"[backup] {path.name} -> {dst}")

def main():
    _check_root()
    backup_dir=ROOT/"backup_before_nextstep_branch_fusion"
    backup_dir.mkdir(exist_ok=True)
    tmp=ROOT/".nextstep_branch_fusion_tmp"
    if tmp.exists(): shutil.rmtree(tmp)
    tmp.mkdir()
    try:
        raw=base64.b64decode(BUNDLE_B64.encode("ascii"))
        with zipfile.ZipFile(io.BytesIO(raw),"r") as z: z.extractall(tmp)
        for name in CORE_FILES:
            src=tmp/name; dst=ROOT/name
            if not src.exists(): raise FileNotFoundError(src)
            _backup(dst, backup_dir)
            shutil.copy2(src,dst)
            print(f"[write] {name}")
        _backup(ROOT/"main_train.py", backup_dir)
        shutil.copy2(ROOT/"main_train_all95_v2.py", ROOT/"main_train.py")
        print("[write] main_train.py <- main_train_all95_v2.py")
        for name in OBSOLETE:
            p=ROOT/name
            if p.exists():
                _backup(p, backup_dir)
                p.unlink()
                print(f"[delete obsolete] {name}")
        print("[patch] stable gated CrossStreamFusionBlock")
        subprocess.check_call([sys.executable, str(ROOT/"patch_model_stable_cross_all95.py")])
        targets=["main_train.py","model.py"]+CORE_FILES[2:]
        print("[check] py_compile")
        subprocess.check_call([sys.executable,"-m","py_compile",*targets])
    finally:
        shutil.rmtree(tmp, ignore_errors=True)
    print("[done] installed Track2 next-step branch-fusion pipeline")

if __name__ == "__main__":
    main()
